{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' \"DESCRIBE user; DESCRIBE review;\"",
  "description": "Inspect user and review tables"
}

{
  "command": "mongosh --quiet 'mongodb://localhost:27017/yelp_db' --eval 'db.business.find({}, {description: 1, _id: 0}).limit(10).toArray().forEach(d => print(d.description))'",
  "description": "Look at a variety of descriptions to understand category format"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' \"SELECT COUNT(*) FROM user WHERE yelping_since LIKE '2016%';\"",
  "description": "Count 2016-registered users"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' \"SELECT r.business_ref, r.date FROM review r JOIN user u ON r.user_id = u.user_id WHERE u.yelping_since LIKE '2016%' AND r.date >= '2016-01-01';\" | head -20\necho \"---count---\"\nduckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' \"SELECT COUNT(*) FROM review r JOIN user u ON r.user_id = u.user_id WHERE u.yelping_since LIKE '2016%' AND r.date >= '2016-01-01';\"",
  "description": "Get reviews from 2016-registered users since 2016"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' \"SELECT COUNT(*) FROM review r JOIN user u ON r.user_id = u.user_id WHERE u.yelping_since LIKE '2016%';\"\necho \"---\"\nduckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' \"SELECT r.business_ref, COUNT(*) as cnt FROM review r JOIN user u ON r.user_id = u.user_id WHERE u.yelping_since LIKE '2016%' GROUP BY r.business_ref ORDER BY cnt DESC;\"",
  "description": "Count all reviews from 2016-registered users"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_yelp/query_dataset/yelp_user.db' \"SELECT DISTINCT REPLACE(r.business_ref, 'businessref_', 'businessid_') as bid, COUNT(*) OVER (PARTITION BY r.business_ref) as cnt FROM review r JOIN user u ON r.user_id = u.user_id WHERE u.yelping_since LIKE '2016%' ORDER BY cnt DESC;\"",
  "description": "Map business refs and count reviews per business"
}
